  1→import * as vscode from "vscode";
  2→import { exec } from "child_process";
  3→import { promisify } from "util";
  4→
  5→const execAsync = promisify(exec);
  6→
  7→const SESSION_NAME_RE = /^koh-(think|explode)-[0-9]+-[a-z0-9-]+$/;
  8→
  9→interface KohSession {
 10→  name: string;
 11→  attached: boolean;
 12→  created: string;
 13→}
 14→
 15→async function listKohSessions(): Promise<KohSession[]> {
 16→  try {
 17→    const { stdout } = await execAsync(
 18→      'tmux list-sessions -F "#{session_name}|#{session_attached}|#{session_created}" 2>/dev/null'
 19→    );
 20→
 21→    return stdout
 22→      .trim()
 23→      .split("\n")
 24→      .filter((line) => SESSION_NAME_RE.test(line.split("|")[0]))
 25→      .map((line) => {
 26→        const [name, attached, created] = line.split("|");
 27→        return {
 28→          name,
 29→          attached: attached === "1",
 30→          created: new Date(parseInt(created) * 1000).toLocaleString(),
 31→        };
 32→      });
 33→  } catch {
 34→    return [];
 35→  }
 36→}
 37→
 38→function attachToSession(sessionName: string) {
 39→  if (!SESSION_NAME_RE.test(sessionName)) {
 40→    vscode.window.showErrorMessage(
 41→      `Invalid koh session name: ${sessionName}`
 42→    );
 43→    return;
 44→  }
 45→
 46→  const terminal = vscode.window.createTerminal({
 47→    name: sessionName,
 48→    shellPath: process.env.SHELL,
 49→    shellArgs: ["-c", `tmux attach-session -t "${sessionName}"`],
 50→    location: vscode.TerminalLocation.Editor,
 51→  });
 52→  terminal.show();
 53→}
 54→
 55→export function activate(context: vscode.ExtensionContext) {
 56→  // Track known sessions to detect new ones
 57→  let knownSessions = new Set<string>();
 58→
 59→  // Initialize known sessions
 60→  listKohSessions().then((sessions) => {
 61→    knownSessions = new Set(sessions.map((s) => s.name));
 62→  });
 63→
 64→  // Poll for new koh tmux sessions every 2 seconds
 65→  const watcher = setInterval(async () => {
 66→    const current = await listKohSessions();
 67→    for (const session of current) {
 68→      if (!knownSessions.has(session.name) && !session.attached) {
 69→        knownSessions.add(session.name);
 70→        const action = await vscode.window.showInformationMessage(
 71→          `koh session detected: ${session.name}`,
 72→          "Attach",
 73→          "Ignore"
 74→        );
 75→        if (action === "Attach") {
 76→          attachToSession(session.name);
 77→        }
 78→      }
 79→    }
 80→    // Update known set (remove gone sessions)
 81→    knownSessions = new Set(current.map((s) => s.name));
 82→  }, 2000);
 83→
 84→  context.subscriptions.push({ dispose: () => clearInterval(watcher) });
 85→
 86→  // Manual attach command
 87→  const attach = vscode.commands.registerCommand("koh.attach", async () => {
 88→    const sessions = await listKohSessions();
 89→
 90→    if (sessions.length === 0) {
 91→      vscode.window.showInformationMessage("No koh sessions running.");
 92→      return;
 93→    }
 94→
 95→    const items = sessions.map((s) => ({
 96→      label: s.name,
 97→      description: s.attached ? "attached" : "",
 98→      detail: `Created: ${s.created}`,
 99→    }));
100→
101→    const pick = await vscode.window.showQuickPick(items, {
102→      placeHolder: "Select a koh session to attach",
103→    });
104→
105→    if (!pick) {
106→      return;
107→    }
108→
109→    attachToSession(pick.label);
110→  });
111→
112→  context.subscriptions.push(attach);
113→}
114→
115→export function deactivate() {}
